INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"layred-card"', '"Prsnt"', '"vanilla"', '{"demo.css": ".layered-card {\n  position: relative;\n\n  /* Demo */\n  height: 6rem;\n  width: 6rem;\n}\n\n.layered-card::before {\n  background: #d1d5db;\n  content: \"\";\n\n  /* Position */\n  top: 0;\n  left: 0;\n  position: absolute;\n  transform: translate(1rem, 1rem);\n\n  /* Size */\n  height: 100%;\n  width: 100%;\n\n  /* Display under the main content */\n  z-index: 0;\n}\n\n.layered-card__content {\n  /* Position */\n  left: 0;\n  position: absolute;\n  top: 0;\n\n  /* Size */\n  height: 100%;\n  width: 100%;\n\n  z-index: 1;\n\n  background: #fff;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Layred Card\r\n    </h1>\r\n    <div class=\"layered-card\">\r\n      <div class=\"layered-card__content\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/layred-card"}'), ('"media-object"', '"Prsnt"', '"vanilla"', '{"demo.css": ".media-object {\n  /* Align sub-items to top */\n  align-items: start;\n  display: flex;\n}\n\n.media-object__media {\n  margin-right: 0.5rem;\n}\n\n.media-object__content {\n  /* Take the remaining width */\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Media Object\r\n    </h1>\r\n    <div class=\"media-object\">\r\n      <!-- Media object -->\r\n      <div class=\"media-object__media\">Object</div>\r\n      <!-- Main content -->\r\n      <div class=\"media-object__content\">Content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/media-object"}'), ('"overlay-paly-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".overlay-play-button {\n  /* Used to position the overlay */\n  position: relative;\n}\n\n.overlay-play-button__overlay {\n  /* Position */\n  left: 0;\n  position: absolute;\n  top: 0;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Add a dark background */\n  background-color: rgba(0, 0, 0, 0.25);\n}\n\n.overlay-play-button__play {\n  border: 0.25rem solid #fff;\n  border-radius: 9999px;\n  height: 3rem;\n  width: 3rem;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Overlay Paly Button\r\n    </h1>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/overlay-paly-button"}'), ('"price-tag"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\n  --price-tag-background: #d1d5db;\n  --price-tag-height: 2rem;\n}\n\n.price-tag {\n  background: var(--price-tag-background);\n  color: #fff;\n\n  /* Center the price */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Used to position the triangle */\n  position: relative;\n\n  /* Size */\n  height: var(--price-tag-height);\n\n  /* Spacing */\n  padding: 0.25rem 0.5rem;\n}\n\n/* The triangle */\n.price-tag::before {\n  content: \"\";\n\n  border-color: transparent var(--price-tag-background) transparent transparent;\n  border-style: solid;\n  border-width: calc(var(--price-tag-height) / 2)\n    calc(var(--price-tag-height) / 2) calc(var(--price-tag-height) / 2) 0rem;\n\n  /* Position */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n  transform: translate(-100%, 0px);\n}\n\n/* The dot */\n.price-tag::after {\n  content: \"\";\n\n  /* Make it like a cirle */\n  background: #fff;\n  border-radius: 9999rem;\n\n  /* Position */\n  left: 0;\n  position: absolute;\n  top: 50%;\n  transform: translate(-0.5rem, -50%);\n\n  /* Size */\n  height: 0.5rem;\n  width: 0.5rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Price Tag\r\n    </h1>\r\n    <div class=\"price-tag\">Price</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/price-tag"}'), ('"pricing-table"', '"Prsnt"', '"vanilla"', '{"Pricing_table.html": "<div class=\"pricing-table\">\n  <!-- Pricing column -->\n  <div class=\"pricing-table__column\">\n    <!-- Title -->\n    ...\n\n    <!-- Price -->\n    ...\n\n    <!-- Description -->\n    ...\n\n    <!-- Button -->\n    ...\n  </div>\n\n  <!-- Repeated pricing columns -->\n  ...\n</div>\n", "demo.css": ".pricing-table {\n  /* Content is centered horizontally */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n}\n\n.pricing-table__column {\n  /* Content is centered vertically */\n  align-items: center;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n\n  /* Make all columns have the same width */\n  flex: 1;\n\n  /* OPTIONAL: Space between columns */\n  margin: 0 0.5rem;\n\n  /* OPTIONAL: Border */\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Pricing Table\r\n    </h1>\r\n    <div class=\"pricing-table\">\r\n      <!-- Pricing column -->\r\n      <div class=\"pricing-table__column\">\r\n        <!-- Title -->\r\n        Title\r\n\r\n        <!-- Price -->\r\n        Price\r\n\r\n        <!-- Description -->\r\n        Description\r\n\r\n        <!-- Button -->\r\n        Button\r\n      </div>\r\n\r\n      <!-- Repeated pricing columns -->\r\n      Repeat Columns here\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/pricing-table"}'), ('"property-list"', '"Prsnt"', '"vanilla"', '{"demo.css": ".property-list {\n  /* Content is center horizontally */\n  align-items: center;\n  display: flex;\n\n  border-bottom: 1px solid #d1d5db;\n\n  /* Spacing */\n  margin: 0;\n  padding: 0.25rem 0;\n}\n.property-list__key {\n  /* Take the available width */\n  flex: 1;\n}\n.property-list__value {\n  margin-left: 0.5rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Property List\r\n    </h1>\r\n    <!-- A property item -->\r\n    <dl class=\"property-list\">\r\n      <!-- Property name -->\r\n      <dt class=\"property-list__key\">Name</dt>\r\n\r\n      <!-- Property value -->\r\n      <dd class=\"property-list__value\">Value</dd>\r\n    </dl>\r\n\r\n    <!-- Repeat other items -->\r\n    Repeat Other Items Here.\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/property-list"}'), ('"questions-and-answers"', '"Prsnt"', '"vanilla"', '{"demo.css": ".questions-and-answers__item:not(:last-child) {\n  border-bottom: 1px solid #d1d5db;\n}\n.questions-and-answers__header {\n  align-items: center;\n  display: flex;\n  justify-content: center;\n  cursor: pointer;\n  padding: 0.5rem;\n}\n.questions-and-answers__toggle {\n  margin-right: 0.25rem;\n}\n.questions-and-answers__title {\n  /* Take the available width */\n  flex: 1;\n}\n.questions-and-answers__content {\n  padding: 0 0.5rem;\n}\n\n.questions-and-answers__item--collapsed .questions-and-answers__content {\n  display: none;\n}\n.questions-and-answers__item--expanded .questions-and-answers__content {\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Questions And Answers\r\n    </h1>\r\n    <!-- Collapsed question and answer item -->\r\n    <div\r\n      class=\"questions-and-answers__item questions-and-answers__item--collapsed\"\r\n    >\r\n      <!-- Heading -->\r\n      <div class=\"questions-and-answers__header\">\r\n        <!-- Question -->\r\n        <div class=\"questions-and-answers__title\">Title</div>\r\n\r\n        <!-- The toggle icon sticks to the right -->\r\n        <div class=\"questions-and-answers__toggle\">Toggle Icon Here</div>\r\n      </div>\r\n\r\n      <!-- Answer -->\r\n      <div class=\"questions-and-answers__content\">Content</div>\r\n    </div>\r\n\r\n    <!-- Expanded question and answer item -->\r\n    <div\r\n      class=\"questions-and-answers__item questions-and-answers__item--expanded\"\r\n    >\r\n      Item1\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/questions-and-answers"}'), ('"ribbon"', '"Prsnt"', '"vanilla"', '{"demo.css": ".ribbon {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Size */\n  height: 2rem;\n\n  /* Use to position the corners */\n  position: relative;\n}\n\n.ribbon__content {\n  /* Background color */\n  background-color: #9ca3af;\n  z-index: 1;\n\n  height: 100%;\n  width: 100%;\n}\n.ribbon__side {\n  bottom: -0.5rem;\n  position: absolute;\n\n  /* Displayed under the ribbon */\n  z-index: 1;\n\n  /* Background */\n  border: 1rem solid #d1d5db;\n}\n\n.ribbon__side--l {\n  /* Position */\n  left: -1.5rem;\n  border-color: #d1d5db #d1d5db #d1d5db transparent;\n}\n\n.ribbon__side--r {\n  /* Position */\n  right: -1.5rem;\n  border-color: #d1d5db transparent #d1d5db #d1d5db;\n}\n\n.ribbon__triangle {\n  position: absolute;\n  top: 100%;\n\n  border: 0.5rem solid transparent;\n  border-bottom-width: 0;\n  border-top-color: #aaa;\n}\n\n.ribbon__triangle--l {\n  border-right-width: 0;\n  left: 0;\n}\n\n.ribbon__triangle--r {\n  border-left-width: 0;\n  right: 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Ribbon\r\n    </h1>\r\n    <div class=\"ribbon\">\r\n      <!-- The left side -->\r\n      <div class=\"ribbon__side ribbon__side--l\"></div>\r\n\r\n      <!-- The left triangle displayed below the content -->\r\n      <div class=\"ribbon__triangle ribbon__triangle--l\"></div>\r\n\r\n      <!-- The right triangle displayed below the content -->\r\n      <div class=\"ribbon__triangle ribbon__triangle--r\"></div>\r\n\r\n      <!-- The right side -->\r\n      <div class=\"ribbon__side ribbon__side--r\"></div>\r\n\r\n      <!-- The content -->\r\n      <div class=\"ribbon__content\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/ribbon"}'), ('"separator"', '"Prsnt"', '"vanilla"', '{"demo.css": ".separator {\n  /* Content is centered horizontally */\n  align-items: center;\n  display: flex;\n\n  /* Used to set the position of text */\n  position: relative;\n}\n\n.separator__content {\n  /* We won''t see the separator line */\n  background: #fff;\n\n  /* Displayed at the center of separator */\n  left: 50%;\n  position: absolute;\n  top: 50%;\n  transform: translate(-50%, -50%);\n\n  /* Spacing */\n  padding: 0 0.25rem;\n\n  /* Demo */\n  width: 60%;\n}\n\n.separator__separator {\n  border-bottom: 1px solid #d1d5db;\n  height: 1px;\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Separator\r\n    </h1>\r\n    <div class=\"separator\">\r\n      <!-- Text -->\r\n      <div class=\"separator__content\">Content</div>\r\n\r\n      <!-- Separator line -->\r\n      <div class=\"separator__separator\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/separator"}'), ('"stacked-card"', '"Prsnt"', '"vanilla"', '{"demo.css": ".stacked-cards {\n  /* Used to position the stacked cards */\n  position: relative;\n\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n}\n\n.stacked-cards__card {\n  /* Absolute position */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Displayed under the container */\n  z-index: 1;\n\n  /* Background and border colors */\n  background-color: rgb(255, 255, 255);\n  border: 1px solid #d1d5db;\n\n  /* Rotate it. Change the number of degrees for the following cards */\n  transform: rotate(5deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Stacked Card\r\n    </h1>\r\n    <div class=\"stacked-cards\">\r\n      <!-- Repeat if you want to have more cards -->\r\n      <div class=\"stacked-cards__card\"></div>\r\n\r\n      <!-- Main card''s content -->\r\n      ...\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/stacked-card"}'), ('"stamp-border"', '"Prsnt"', '"vanilla"', '{"demo.css": ".stamp-border {\n  /* Background */\n  background-color: #d1d5db;\n  background-image: radial-gradient(#fff 50%, transparent 50%);\n  background-position: -0.25rem -0.25rem;\n  background-repeat: repeat;\n  background-size: 0.5rem 0.5rem;\n\n  /* Spacing */\n  padding: 0.25rem;\n}\n\n.stamp-border__content {\n  /* Background */\n  background-color: #d1d5db;\n\n  height: 100%;\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Stamp Border\r\n    </h1>\r\n    <div class=\"stamp-border\">\r\n      <div class=\"stamp-border__content\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/stamp-border"}'), ('"statistics"', '"Prsnt"', '"vanilla"', '{"demo.css": ".statistic {\n  /* Center the content */\n  align-items: center;\n  display: inline-flex;\n  flex-direction: column;\n}\n\n.statistic__value {\n  /* Big font size */\n  font-size: 4rem;\n  font-weight: 500;\n}\n\n.statistic__label {\n  /* Smaller font size */\n  font-size: 1rem;\n  font-weight: 700;\n\n  /* Uppercase the label */\n  text-transform: uppercase;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Statistics\r\n    </h1>\r\n    <div class=\"statistic\">\r\n      <!-- Value -->\r\n      <div class=\"statistic__value\">Value</div>\r\n\r\n      <!-- Label -->\r\n      <div class=\"statistic__label\">Label</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/statistics"}'), ('"status-light"', '"Prsnt"', '"vanilla"', '{"demo.css": ".status-light {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n}\n\n.status-light__status {\n  /* Background color */\n  background-color: #16a34a;\n\n  /* Rounded border */\n  border-radius: 9999px;\n\n  /* Size */\n  height: 0.5rem;\n  width: 0.5rem;\n\n  /* Spacing */\n  margin-right: 0.5rem;\n}\n\n.status-light__content {\n  /* Take available width */\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Status Light\r\n    </h1>\r\n    <div class=\"status-light\">\r\n      <!-- Status light -->\r\n      <div class=\"status-light__status\"></div>\r\n\r\n      <!-- Content -->\r\n      <div class=\"status-light__content\">Content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/status-light"}'), ('"sticky-table-column"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sticky-table-headers__sticky {\n  /* Background color */\n  background-color: #9ca3af;\n\n  /* Stick to the left */\n  left: 0;\n  position: sticky;\n\n  /* Displayed on top of other rows when scrolling */\n  z-index: 9999;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sticky Table Column\r\n    </h1>\r\n    <table class=\"sticky-table-column\">\r\n      <thead>\r\n        <tr>\r\n          <th class=\"sticky-table-column__sticky\">...</th>\r\n\r\n          <!-- Other header column ... -->\r\n        </tr>\r\n      </thead>\r\n      <tbody>\r\n        <tr>\r\n          <td class=\"sticky-table-column__sticky\">...</td>\r\n          <!-- Other columns ... -->\r\n        </tr>\r\n      </tbody>\r\n    </table>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/sticky-table-column"}'), ('"sticky-table-headers"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sticky-table-headers__sticky {\n  /* Background color */\n  background-color: #9ca3af;\n\n  /* Stick to the left */\n  left: 0;\n  position: sticky;\n\n  /* Displayed on top of other rows when scrolling */\n  z-index: 9999;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sticky Table Headers\r\n    </h1>\r\n    <table class=\"sticky-table-headers\">\r\n      <thead>\r\n        <tr class=\"sticky-table-headers__sticky\">\r\n          Header\r\n        </tr>\r\n      </thead>\r\n      <tbody>\r\n        Body\r\n      </tbody>\r\n    </table>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/sticky-table-headers"}'), ('"teardrop"', '"Prsnt"', '"vanilla"', '{"demo.css": ".teardrop {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Border */\n  border: 2px solid #d1d5db;\n  border-radius: 0px 50% 50% 50%;\n\n  /* Angle at the top */\n  transform: rotate(45deg);\n\n  /* Size */\n  height: 4rem;\n  width: 4rem;\n}\n\n.teardrop__content {\n  transform: rotate(-45deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Teardrop\r\n    </h1>\r\n    <div class=\"teardrop\">\r\n      <!-- Display the content vertically -->\r\n      <div class=\"teardrop__content\">Content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/teardrop"}'), ('"three-dimensions-card"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\n  --three-dimensions-card-left-side-width: 1rem;\n}\n\n.three-dimensions-card {\n  position: relative;\n}\n\n/* The left side */\n.three-dimensions-card::before {\n  background: #d1d5db;\n  content: \"\";\n\n  /* Position */\n  top: var(--three-dimensions-card-left-side-width);\n  left: 0px;\n  position: absolute;\n  transform: translate(-100%, 0) skewY(-45deg);\n  transform-origin: left top;\n\n  /* Size */\n  height: 100%;\n  width: var(--three-dimensions-card-left-side-width);\n}\n\n/* The bottom side */\n.three-dimensions-card::after {\n  background: #d1d5db;\n  content: \"\";\n\n  /* Position */\n  bottom: 0px;\n  left: 0px;\n  position: absolute;\n  transform: translate(0, 100%) skewX(-45deg);\n  transform-origin: left top;\n\n  /* Size */\n  height: var(--three-dimensions-card-left-side-width);\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Three Dimensions Card\r\n    </h1>\r\n    <div class=\"three-dimensions-card\">Card</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/three-dimensions-card"}'), ('"timeline"', '"Prsnt"', '"vanilla"', '{"demo.css": ".timeline {\n  /* Used to position the left vertical line */\n  position: relative;\n}\n\n.timeline__line {\n  /* Border */\n  border-right: 2px solid #d1d5db;\n\n  /* Positioned at the left */\n  left: 0.75rem;\n  position: absolute;\n  top: 0px;\n\n  /* Take full height */\n  height: 100%;\n}\n\n.timeline__items {\n  /* Reset styles */\n  list-style-type: none;\n  margin: 0px;\n  padding: 0px;\n}\n\n.timeline__item {\n  margin-bottom: 8px;\n}\n\n.timeline__top {\n  /* Center the content horizontally */\n  align-items: center;\n  display: flex;\n}\n\n.timeline__circle {\n  /* Rounded border */\n  background-color: #d1d5db;\n  border-radius: 9999px;\n\n  /* Size */\n  height: 1.5rem;\n  width: 1.5rem;\n}\n\n.timeline__title {\n  /* Take available width */\n  flex: 1;\n  margin-left: 0.5rem;\n}\n\n.timeline__desc {\n  /* Make it align with the title */\n  margin-left: 2rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Timeline\r\n    </h1>\r\n    <div class=\"timeline\">\r\n      <!-- Left vertical line -->\r\n      <div class=\"timeline__line\"></div>\r\n\r\n      <!-- The timeline items timeline -->\r\n      <div class=\"timeline__items\">\r\n        <!-- Each timeline item -->\r\n        <div class=\"timeline__item\">\r\n          <!-- The circle and title -->\r\n          <div class=\"timeline__top\">\r\n            <!-- The circle -->\r\n            <div class=\"timeline__circle\"></div>\r\n\r\n            <!-- The title -->\r\n            <div class=\"timeline__title\">Title</div>\r\n          </div>\r\n\r\n          <!-- The description -->\r\n          <div class=\"timeline__desc\">Descsription</div>\r\n        </div>\r\n\r\n        <!-- Repeat other items -->\r\n        Repeat other items\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/timeline"}'), ('"toggle-switch"', '"Prsnt"', '"vanilla"', '{"demo.css": ".switch {\n  position: relative;\n  display: inline-block;\n  width: 40px;\n  height: 20px;\n  background-color: rgba(0, 0, 0, 0.25);\n  border-radius: 20px;\n  transition: all 0.3s;\n}\n\n.switch::after {\n  content: '''';\n  position: absolute;\n  width: 18px;\n  height: 18px;\n  border-radius: 18px;\n  background-color: white;\n  top: 1px;\n  left: 1px;\n  transition: all 0.3s;\n}\n\ninput[type=''checkbox'']:checked + .switch::after {\n  transform: translateX(20px);\n}\n\ninput[type=''checkbox'']:checked + .switch {\n  background-color: #7983ff;\n}\n\n.offscreen {\n  position: absolute;\n  left: -9999px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Toggle Switch\r\n    </h1>\r\n    <input type=\"checkbox\" id=\"toggle\" class=\"offscreen\" />\r\n    <label for=\"toggle\" class=\"switch\"></label>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/toggle-switch"}'), ('"tree-diagram"', '"Prsnt"', '"vanilla"', '{"demo.css": ".tree-diagram ul {\n  display: flex;\n  position: relative;\n\n  /* Reset */\n  list-style-type: none;\n  margin: 0;\n  padding: 1rem 0.5rem 0rem 0.5rem;\n}\n\n.tree-diagram ul ul::before {\n  border-right: 1px solid #d1d5db;\n  content: \"\";\n\n  /* Position */\n  position: absolute;\n  top: 0;\n  right: 50%;\n\n  /* Size */\n  height: 1rem;\n  width: 50%;\n}\n\n.tree-diagram li {\n  padding: 1rem 0.5rem 0rem 0.5rem;\n  position: relative;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  flex-direction: column;\n}\n\n.tree-diagram li::before {\n  border-right: 1px solid #d1d5db;\n  border-top: 1px solid #d1d5db;\n  content: \"\";\n\n  /* Position */\n  position: absolute;\n  top: 0;\n  right: 50%;\n\n  /* Size */\n  height: 1rem;\n  width: 50%;\n}\n\n.tree-diagram li::after {\n  border-top: 1px solid #d1d5db;\n  content: \"\";\n\n  /* Position */\n  position: absolute;\n  top: 0;\n  right: 0;\n\n  /* Size */\n  width: 50%;\n}\n\n.tree-diagram li:first-child::before,\n.tree-diagram li:last-child::after {\n  /* Remove the top of border from the first and last items */\n  border-top: none;\n}\n\n/* Add a root item if you want */\nli.tree-diagram__root::before {\n  border-right: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Tree Diagram\r\n    </h1>\r\n    <div class=\"tree-diagram\">\r\n      <ul>\r\n        <!-- You can add a root item to the tree -->\r\n        <li class=\"tree-diagram_root\">gh-pages</li>\r\n        <li>\r\n          <!-- Content -->\r\n          feature\r\n\r\n          <!-- Sub items -->\r\n          <ul>\r\n            <li>\r\n              <!-- Content -->\r\n              Story\r\n\r\n              <!-- Sub items -->\r\n              <ul>\r\n                <li>Task</li>\r\n                <li>Task</li>\r\n                Subtask\r\n              </ul>\r\n            </li>\r\n            <li>Another Story</li>\r\n            ...\r\n          </ul>\r\n        </li>\r\n\r\n        <!-- Repeat other items -->\r\n        ...\r\n      </ul>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/tree-diagram"}');